import React from "react";
import Icon from "../assets/gem.png";

function Footer() {
  return (
    <footer className="bg-gradient-to-r from-purple-800 via-purple-700 to-purple-300 text-white shadow-md mt-16">
      <div className="max-w-7xl mx-auto px-6 py-8 md:py-12">
        <div className="sm:flex sm:items-center sm:justify-between">
          {/* Logo */}
          <a href="/" className="flex items-center mb-4 sm:mb-0 space-x-3">
            <img src={Icon} className="h-8" alt="GemAnalyzer Logo" />
            <span className="self-center text-2xl font-bold whitespace-nowrap">
              GemAnalyzer
            </span>
          </a>

          
        </div>

        <hr className="my-6 border-white/30 sm:mx-auto lg:my-8" />

        {/* Copyright */}
        <span className="block text-sm sm:text-center">
          © 2026 GemAnalyzer. All Rights Reserved.
        </span>
      </div>
    </footer>
  );
}

export default Footer;
